14	interface Scenario {
15	  customer: Customer;
16	  steps: QuoteStep[];
17	}
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	};
23	
24	const PROCESSING_FEE = 5;
25	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
26	
27	const quotePremium = (step: QuoteStep): number => {
28	  let total = 0;
29	  for (const item of step.items) {
30	    const base = BASE_PREMIUM[item.type];
31	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
32	  }
33	  return Math.ceil(total) + PROCESSING_FEE;
34	};
35	
36	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
37	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
38	  return { results };
39	};
